import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Heart, ListPlus, Play, Pause, Trophy, Music, User } from 'lucide-react';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef(null);
  const navigate = useNavigate();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
  }, []);

  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleCreatePlaylist = async () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Tên Playlist mới:");
    if (!title) return;
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title, userId: loggedInUser._id, songIds: []
      });
      alert("Đã tạo Playlist thành công! 🎉");
    } catch (err) { alert("Lỗi tạo playlist"); }
  };

  const playSong = (index) => {
    setCurrentIndex(index);
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'Arial, sans-serif' }}>
      
      {/* HEADER: Nút chức năng */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Music size={32} /> P2TUNES
        </h1>
        
        <div style={{ display: 'flex', gap: '15px' }}>
          <button onClick={() => navigate('/ranking')} style={btnSecondary}>
            <Trophy size={18} /> BXH Lượt Like
          </button>
          
          <button onClick={handleCreatePlaylist} style={btnPrimary}>
            <ListPlus size={18} /> TẠO PLAYLIST
          </button>

          {loggedInUser && (
            <button onClick={() => navigate(`/profile/${loggedInUser._id}`)} style={btnSecondary}>
              <User size={18} /> Hồ sơ
            </button>
          )}
        </div>
      </div>

      {/* GRID NHẠC */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '25px' }}>
        {songs.map((song, index) => (
          <div key={song._id} style={songCard}>
            <div style={{ position: 'relative' }}>
              <img 
                src={`http://localhost:5000${song.imageUrl}`} 
                alt={song.title} 
                style={imgStyle} 
              />
              <button onClick={() => playSong(index)} style={playOverlayBtn}>
                <Play fill="white" />
              </button>
            </div>
            
            <h3 style={{ margin: '15px 0 5px 0', fontSize: '16px' }}>{song.title}</h3>
            <p style={{ color: '#666', fontSize: '14px', margin: '0 0 10px 0' }}>{song.artist}</p>
            
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <button onClick={() => handleLike(song._id)} style={likeBtnStyle}>
                <Heart 
                  size={20} 
                  fill={song.likes?.includes(loggedInUser?._id) ? "red" : "none"} 
                  color={song.likes?.includes(loggedInUser?._id) ? "red" : "#666"} 
                />
                <span style={{ fontWeight: 'bold' }}>{song.likes?.length || 0}</span>
              </button>
              
              <span style={{ fontSize: '12px', color: '#1db954', cursor: 'pointer' }} onClick={() => navigate(`/profile/${song.userId}`)}>
                @{song.uploaderName || 'User'}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* TRÌNH PHÁT NHẠC ĐƠN GIẢN Ở DƯỚI CÙNG */}
      {currentIndex !== -1 && (
        <div style={playerContainer}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px', width: '300px' }}>
            <img src={`http://localhost:5000${songs[currentIndex].imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px' }} alt="" />
            <div>
              <div style={{ fontWeight: 'bold' }}>{songs[currentIndex].title}</div>
              <div style={{ fontSize: '12px', color: '#888' }}>{songs[currentIndex].artist}</div>
            </div>
          </div>

          <div style={{ flex: 1, textAlign: 'center' }}>
            <button onClick={togglePlay} style={mainPlayBtn}>
              {isPlaying ? <Pause size={24} /> : <Play size={24} />}
            </button>
            <audio 
              ref={audioRef} 
              src={`http://localhost:5000${songs[currentIndex].songUrl}`} 
              autoPlay 
              onPlay={() => setIsPlaying(true)}
              onPause={() => setIsPlaying(false)}
            />
          </div>
          
          <div style={{ width: '300px' }}></div>
        </div>
      )}
    </div>
  );
};

/* --- STYLES --- */
const btnPrimary = {
  background: '#ffffff',
  color: '#000000',
  border: '2px solid #000',
  padding: '10px 20px',
  borderRadius: '25px',
  fontWeight: '900', // CHỮ ĐEN ĐẬM
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  fontSize: '14px'
};

const btnSecondary = {
  background: '#f4f4f4',
  border: '1px solid #ddd',
  padding: '10px 20px',
  borderRadius: '25px',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  fontWeight: 'bold'
};

const songCard = {
  background: '#fff',
  padding: '15px',
  borderRadius: '15px',
  boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
  transition: 'transform 0.2s'
};

const imgStyle = {
  width: '100%',
  aspectRatio: '1/1',
  objectFit: 'cover',
  borderRadius: '10px'
};

const playOverlayBtn = {
  position: 'absolute',
  bottom: '10px',
  right: '10px',
  background: '#1db954',
  border: 'none',
  borderRadius: '50%',
  width: '40px',
  height: '40px',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  color: 'white'
};

const likeBtnStyle = {
  background: 'none',
  border: 'none',
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
  cursor: 'pointer',
  color: '#666'
};

const playerContainer = {
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  background: '#fff',
  borderTop: '1px solid #eee',
  padding: '15px 40px',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  boxShadow: '0 -5px 20px rgba(0,0,0,0.05)'
};

const mainPlayBtn = {
  background: '#1db954',
  color: 'white',
  border: 'none',
  width: '50px',
  height: '50px',
  borderRadius: '50%',
  cursor: 'pointer',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center'
};

export default Home;
